function LBattleViewMgr:Initialize()
    self._isInitOk = false
    self._isLoaded = false
    self._effectMgr = require("LApp.gameplay.videobattle.view.LBattleViewEffectMgr"):new()
    self._effectMgr:Initialize()
    self._unitMgr = require("LApp.gameplay.videobattle.view.LBattleViewUnitMgr"):new()
    self._unitMgr:Initialize()
    self._viewFace = require("LApp.gameplay.videobattle.view.LBattleViewFace"):new()
    self._viewFace:Initialize()

    self._hurtCounter = require("LApp.gameplay.videobattle.view.LFightHurtCounter"):new()
    self._buffActMgr = require("LApp.gameplay.videobattle.view.LBattleViewBuffActMgr"):new()
    self._buffActMgr:Initialize()


    self._unitMgr:SetViewMgr(self)
    self._effectMgr:SetViewMgr(self)
    self._viewFace:SetViewMgr(self)

    self._buffActMgr:SetViewMgr(self)
end

