function LBattleViewMgr:OnLoadedAll()
    local startType = self._startType
    self._unitMgr:ClearCallback()
    if startType == BattleStartType.LikeResumeLive then
        self._runStep = _Run_Step.Play
        self._unitMgr:ResumeBattle()
        self._logicMgr:PlayBattle()
    elseif startType == BattleStartType.LikeReplay then
        self._runStep = _Run_Step.DelayStart
        self:ReadyBattle()
        self._delayStartTime = 1
    elseif startType == BattleStartType.LikeNewStart then
        self._runStep = _Run_Step.DelayStart
        self._delayStartTime = 1
    end
end

---异步加载问题修改
function LBattleViewMgr:OnUiReady(viewMode)
    if self._isUiReady then return end
    if viewMode ~= self._showMode then return end
    self._isUiReady = true
    self:OnViewReady()
end

function LBattleViewMgr:OnViewReady()
    if not self._isUiReady or not self._isLoaded then return end
    self._runStep = _Run_Step.WaitViewReady
end

function LBattleViewMgr:DoViewReady()
    self._runStep = _Run_Step.ViewReady
    FireEvent(EventNames.BATTLE_VIEW_INIT, {unitMap = self._unitMgr:GetUnitMap(), isShowStart=true})
    if self._showMode == BattleViewMode.Battle then
        self:OnLoadedAll()
    end
end

function LBattleViewMgr:IsLoaded()
    return self._isLoaded
end

function LBattleViewMgr:OnScreenSizeChange()
    if not self._isInitOk then
        return
    end
    if self._viewFace then
        self._viewFace:UpdateOrthographicSize()
    end
end

function LBattleViewMgr:InitBattleView()
    if self._isInitOk then
        return
    end
    ---@type LxBattleAdapter
    local battleAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.Battle)
    local mapTrans = battleAdapter:GetMapTrans()
    if IsNull(mapTrans) then
        return
    end

    self._formationNode = mapTrans:Find("ShakeRoot/FormationRoot").gameObject
    self._controlNode = mapTrans:Find("ControlRoot").gameObject
    self._effectNode = mapTrans:Find("EffectRoot").gameObject

    self._formationCenter = mapTrans:Find("ShakeRoot/FormationRoot/FormationCenter")

    if IsNull(self._formationNode) or IsNull(self._controlNode) then
        return
    end
    self._viewFace:SetMapRoot(mapTrans)
    self._unitMgr:SetRootNode(self._formationNode)
    self._effectMgr:SetRootNode(self._effectNode)
    self._effectMgr:SetFormationCenter(self._formationCenter)

    self._isInitOk = true
    self._isPause = false
end

function LBattleViewMgr:Reset()
    if self._agent then
        self._agent:SetViewMgr(nil)
        self._agent = nil
    end
    self._runStep = _Run_Step.None
    self._delayStartTime = 0
end

---@param logicMgr LBattleLogicMgr
function LBattleViewMgr:ShowBattle(logicMgr, startType)
    self:Reset()
    self._isFormationEdit = false
    self._startType = startType

    self._isLoaded = false
    self._isUiReady = false

    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.Battle)
    if ctrl and ctrl:IsPanelReady() then
        self._isUiReady = true
    end

    self._agent = logicMgr:GetAgent()
    self._agent:SetViewMgr(self)

    local config = logicMgr:GetBattleConfig()
    self._battleConfig = config
    self._showMode = BattleViewMode.Battle
    self._reportId = logicMgr:GetReportId()
    self._logicMgr = logicMgr

    self._combatType = self._logicMgr:GetBattleType()

    ---暂停logicMgr的播放
    logicMgr:SetAutoNext(false, false)
    logicMgr:SetProtectOnToFront()

    self._viewFace:SetBattleConfig(config)
    self._unitMgr:SetBattleConfig(config)
    self._unitMgr:SetBattle(logicMgr, function()
        self._isLoaded = true
        self:InitTeamHP()
        self:OnViewReady()
    end)
end

---@param formation1 LxFormationObj
---@param formation2 LxFormationObj
---@param config V_Battle_BattleConfig
function LBattleViewMgr:ShowFormation(config, formation1, formation2)
    if not self._isInitOk then return end
    self:Reset()
    self._isLoaded = false
    self._isUiReady = false
    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.Formation)
    if ctrl and ctrl:IsPanelReady() then
        self._isUiReady = true
    end
    self._battleConfig = config
    self._combatType = config and config.battleType or BattleType.Adventure
    self._showMode = BattleViewMode.Formation
    self._isFormationEdit = config.showMode == BattleViewMode.Formation
    self._viewFace:SetBattleConfig(config)
    self._unitMgr:SetBattleConfig(config)
    self._viewFace:SetFormationId(formation1 and formation1.formationRefId, formation2 and formation2.formationRefId)

    if formation1 then
        self._unitMgr:SetFormation(formation1, formation2, function()
            self._isLoaded = true
            FireEvent(EventNames.BATTLE_VIEW_INIT, {unitMap = self._unitMgr:GetUnitMap()})
        end)
    else
        self._unitMgr:SetEmpty()
    end
end

