function LBattleViewMgr:ClearView()
    if self._effectMgr then
        self._effectMgr:ClearAll()
    end
    if self._unitMgr then
        self._unitMgr:SetupAll()
    end
    if self._viewFace then
        self._viewFace:ClearAll()
    end

    if self._runningSkillPlayers then
        local cnt = #self._runningSkillPlayers
        while cnt > 0 do
            cnt = cnt - 1
            local player = table.remove(self._runningSkillPlayers)
            player:Dispose()
        end
    end

    self._runStep = _Run_Step.AllFinished
end


