function LBattleViewMgr:CheckPlayStart(deltaTime)
    if self._delayStartTime > 0 then
        self._delayStartTime = self._delayStartTime - deltaTime
        if self._delayStartTime <= 0 then
            self._runStep = _Run_Step.Play
            self._logicMgr:PlayBattle()
        end
    end
end

function LBattleViewMgr:OnUpdate(time, deltaTime)
    if not self._isInitOk or self._isPause then
        return
    end

    if self._isDisposed then return end

    local bBattleMode = self._showMode == BattleViewMode.Battle

    self._time = time

    if self._unitMgr then
        self._unitMgr:OnUpdate(time, deltaTime)
    end

    if self._effectMgr then
        self._effectMgr:OnUpdate(time, deltaTime)
    end

    if self._viewFace then
        self._viewFace:OnUpdate(time, deltaTime)
    end

    if bBattleMode then
        self:_OnBattleUpdate(time, deltaTime)
    end
end

function LBattleViewMgr:_OnBattleUpdate(time, deltaTime)
    if self._runStep == _Run_Step.WaitViewReady then
        self:DoViewReady()
    end
    if self._runStep == _Run_Step.DelayStart then
        self:CheckPlayStart(deltaTime)
    end

    FireEvent(EventNames.BATTLE_SYNC_VIEW_TIME, time)

    if self._runStep ~= _Run_Step.Play and self._runStep ~= _Run_Step.LastShow then
        return
    end


    --self:UpdateChase(time)

    --while(self:IsOfflineRound())  do
    --    self:CheckNextPlay()
    --end
    
    local players = self._runningSkillPlayers
    local playerCount = players and #players or 0
    if playerCount > 0 then
        local removeIndexList = {}
        for i, player in ipairs(players) do
            if not player:OnUpdate(time, deltaTime) then
                --- 技能同组表现，再最后一组隐藏血条
                player:NeedResetBlock(playerCount == 1)
                player:ResetHeroesBgState()
                player:Dispose()
                table.insert(removeIndexList,i)
            end
        end
        local removeLen = #removeIndexList
        for i=removeLen, 1, -1 do
            table.remove(players,removeIndexList[i])
        end
        if removeLen > 0 then
            FireEvent(EventNames.BATTLE_CHANGE_WND_SHOW,true)
        end
    end

    self:UpdateHurtCount(time)
    self:OnObjRoundUpdate()

    self._buffActMgr:OnUpdate(time, deltaTime)

    if self._curRoundIndex == 1 then --回合0，直接尝试执行10小人的被动技能
        local cnt = 10
        while(cnt > 0) do
            if not self:CheckSkillPlayerFinished(true) then
                cnt = cnt - 1
            else
                break
            end
        end
    else
        self:CheckSkillPlayerFinished()
    end
end

function LBattleViewMgr:CheckSkillPlayerFinished(forceExecute)
    local isSkillEnd = #self._runningSkillPlayers == 0
    local isBuffEnd = self._buffActMgr:IsNoBuff()
    if isSkillEnd and isBuffEnd then
        local needWait = self:WaitDeadShow()
        local waitDeadAction = self:CheckWaitDeadAction()
        if not needWait and not waitDeadAction then
            self._agent:C2S_SetViewActFinish(true)
            if forceExecute then
                self._agent:C2S_ExecuteNext()
            end
        end
    else
        return true
    end
end

function LBattleViewMgr:WaitDeadShow()
    local objList = self._unitMgr:GetUnitMap()
    for k,v in pairs(objList) do
        if v:HasDeadShowList() then
            return true
        end
    end

    return false
end

