--预备下一个播放,主要是预加载技能特效
function LBattleViewMgr:PreloadRoundPlay(roundIndex, boutIndex, actionIndex)
    local preloadSkill = self._preloadSkill
    if preloadSkill then
        local state = self:GetPreloadState(preloadSkill,roundIndex, boutIndex, actionIndex)
        if state == 1 then
            self:ClearPreloadSkill()
        elseif state == 2 or state == 3 then
            return
        end
    end

    self._isLastAtk = false

    if roundIndex > self._totalRoundIndex  or self._isBackgroundPlay then
        self._isLastAtk = true
        return
    end

    local roundDataList = self._battleReportData:GetRoundDataList()
    local roundData = roundDataList[roundIndex]
    -- try get bout
    local boutData = roundData and roundData:GetBout(boutIndex) or nil
    if boutData == nil then
        self:PreloadRoundPlay(roundIndex + 1, 1, 1)
        return
    end

    -- try get action
    local actionDataList = boutData and boutData:GetAction(actionIndex) or {}
    if #actionDataList == 0 then
        self:PreloadRoundPlay(roundIndex, boutIndex + 1, 1)
        return
    end

    local dataMgr = self._dataMgr


    -- reload action bt actionData
    local index = 1
    local list = {}
    for i, actionData in ipairs(actionDataList) do
        local aId = actionData:GetAttackId()
        local skillRefId = actionData:GetSkill()
        local expressionRefId = actionData:GetExpress()

        local heroData = self:GetHeroData(aId)
        local hurtCount = self:GetHurtCountFromActionData(actionData)
        local atkHero = self:GetUnitView(aId)
        local isChangeSpine = false
        if atkHero and not atkHero:IsDead() then
            isChangeSpine = atkHero:GetChangeSpineState()
        end
        local skillData
        if heroData then
            local isCreateSkillData = false
            if isChangeSpine then
                --- 变身下，直接从皮肤拿表现
                local expressionId = dataMgr:GetSkinExpress(atkHero:GetSkinId(),expressionRefId,true)
                if expressionId and expressionId > 0 then
                    skillData = heroData:GetSkillTransformData(skillRefId,expressionId,expressionRefId) or nil
                    isCreateSkillData = skillData ~= nil
                    if isCreateSkillData then
                        local skill = LBattleSkillPlayer:new(self)
                        skill:Initialize(skillData,atkHero,actionData)
                        skill:PreloadPlayList()
                        list[index] = skill
                        index = index + 1
                    end
                    skillData = nil
                end
            end
            if not isCreateSkillData then
                skillData = heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
            end
        end
        if skillData and atkHero then
            ---@type LFightSkill
            local skill = LFightSkill:New(self,skillData,atkHero,actionData)
            skill:PreloadPlayList()
            list[index] = skill
            index = index + 1
        end
    end

    if table.keysize(list) == 0 then
        self:PreloadRoundPlay(roundIndex,boutIndex,actionIndex + 1)
        return
    end

    local data = {
        round = roundIndex,
        bout = boutIndex,
        action = actionIndex,
        skillList = list
    }

    self._preloadSkill = data

end

---state 1 passed,2 current ,3 future
function LBattleViewMgr:GetPreloadState(preloadSkill,roundIndex,boutIndex,actionIndex)
    local state = nil
    if roundIndex < preloadSkill.round then
        state = 3
    elseif roundIndex == preloadSkill.round then
        if boutIndex < preloadSkill.bout then
            state = 3
        elseif boutIndex == preloadSkill.bout then
            if actionIndex < preloadSkill.action then
                state = 3
            elseif actionIndex == preloadSkill.action then
                state = 2
            else
                state = 1
            end
        else
            state = 1
        end
    else
        state = 1
    end

    return state
end

function LBattleViewMgr:GetFirstSkillData()
    local roundDataList = self._battleReportData:GetRoundDataList()
    local maxRound = self._battleReportData:GetTotalRound()
    local curRoundIndex = self._agent:GetCurRoundIndex()
    local curBoutIndex = self._agent:GetCurBoutIndex()
    local curActionIndex = self._agent:GetCurActionIndex()
    local initR = curRoundIndex > 0 and curRoundIndex or 0
    local initB = curBoutIndex > 0 and curBoutIndex or 0
    local initA = curActionIndex + 1
    for round = initR,maxRound do
        local roundData = roundDataList[round]
        local maxBout = roundData:GetBoutCount()
        for bout = initB, maxBout do
            local boutData = roundData:GetBout(bout)
            local maxAction = boutData:GetActionTotalCount()
            for action = initA ,maxAction do
                local actionDataList = boutData:GetAction(action)
                for k,v in ipairs(actionDataList.list) do
                    local aId = v.aId
                    local skillRefId = v.skill
                    local expressionRefId = v.express

                    local heroData = self:GetHeroData(aId)
                    local hurtCount = self:GetHurtCountFromActionData(v)
                    local atkHero = self:GetUnitView(aId)
                    local skillData = heroData and heroData:GetSkillData(skillRefId,expressionRefId,hurtCount) or nil
                    if skillData and atkHero then
                        return skillData,atkHero
                    end
                end
            end
        end
    end
end

function LBattleViewMgr:PreloadFirstSkillEff()
    self._effectNeedPreLoadLen = 0
    self._effectPreloadLen = 0

    local skillData,atkHero= self:GetFirstSkillData()
    if not skillData then
        self:OnEffectPreloaded()
        return
    end

    local effList = skillData:GetPlayEffList()

    local treaEff = nil
    local effDataList = {}
    for k,v in ipairs(effList) do
        local effType = v.effType
        if LSkillEffConst.PRELOAD_EFFECT_MAP[effType] then
            table.insert(effDataList,v)
        elseif effType == LSkillEffConst.PLAY_EFF_TREASURE then
            treaEff = v
        end
    end

    if #effDataList>0 then
        local effTask =
        {
            effList = effDataList,
            endFunc = function() self:OnEffectPreloaded() end,
        }

        self._effectNeedPreLoadLen = self._effectNeedPreLoadLen + 1
        local effectCtrl = self:GetEffectCtrl()
        effectCtrl:PreloadEffList(effTask,atkHero)
    end

    if treaEff then
        local heroId = atkHero:GetId()
        self._effectNeedPreLoadLen = self._effectNeedPreLoadLen + 1
        if self._treaObjCtrl then
            self._treaObjCtrl:LoadObj(heroId,treaEff,function ()
                self:OnEffectPreloaded()
            end)
        end
    end


    if self._effectNeedPreLoadLen== 0 then
        self:OnEffectPreloaded()
    end
end

function LBattleViewMgr:OnEffectPreloaded()
    self._effectPreloadLen = self._effectPreloadLen + 1
    if self._effectPreloadLen < self._effectNeedPreLoadLen then
        return
    end
    self._firstEffLoaded = true
end


