function LBattleViewMgr:GetRowCenterPos(side,targetGrid)
    local grids = side == BattleTeamSide.teamA and self._viewFace._mapFormation1Grid or self._viewFace._mapFormation2Grid
    local gridIndex = Mathf.Clamp(targetGrid,1,9)
    local centerIndex =  math.floor((gridIndex - 1) / 3) * 3 + 2
    local pos = grids[centerIndex]:Clone()

    return pos
end

