function LBattleViewMgr:GetGridPosByIndex(side,index)
    local posMap = nil
    if side == BattleTeamSide.teamA then
        posMap = self._viewFace._mapFormation1Grid
    else
        posMap = self._viewFace._mapFormation2Grid
    end

    return posMap[index]
end

function LBattleViewMgr:DoShake(time, x, y)
    self._viewFace:PlayShake(time, x, y)
end


function LBattleViewMgr:IsStartPlay()
    return self._isStartPlay
end

function LBattleViewMgr:GetSpeed()
    return self._agent:GetSpeed()
end

---检测所有出生动画播放完毕
function LBattleViewMgr:OnPlayBirthEnd()
    self._nowHeroBirthLen = self._nowHeroBirthLen + 1
    if(self._nowHeroBirthLen < self._totalHeroBirthLen) then return end
    self:PreparePlay()
end

function LBattleViewMgr:PlayBirth()      ---检查修正   移动进场未完善
    --以所有在战场英雄最长的进场动画时间为准 （留个默认值，防止某些情况下获取不到数据）
    local objCtrl = self:GetUnitMgr()
    local objList = objCtrl:GetUnitMap()

    local endFunc = function()
        self:OnPlayBirthEnd()
    end



    self._nowHeroBirthLen = 0

    local totalBirth = 0
    for k,v in pairs(objList) do
        if not v:IsDead() then
            totalBirth = totalBirth + 1
        end
    end
    self._totalHeroBirthLen = totalBirth

    for k,v in ipairs(objList) do
        if not v:IsDead() then
            v:ShowBirth(endFunc)
        end
    end
end

function LBattleViewMgr:GetCurSpeedDataList()
    return self._agent:GetCurSpeedDataList()
end

function LBattleViewMgr:IsHeroPlayed(id)
    return self._logicMgr:IsHeroPlayed(id)
end
