---获取伤害次数
---@param actionData LFightBoutActionData
function LBattleViewMgr:GetHurtCountFromActionData(actionData)
    return self._agent:GetHurtCountFromActionData(actionData)
end
-----------------------------------------------------------------
function LBattleViewMgr:AddHurtCnt(side,hurt)
    local curHurt = self._teamHurtCnt[side] or 0
    curHurt = curHurt + hurt
    self._teamHurtCnt[side] = curHurt
end

function LBattleViewMgr:InitShowHurtCnt()
    if not self._teamShowHurtCnt then
        self._teamShowHurtCnt = {}
        self._teamShowHurtCnt[BattleTeamSide.teamA] = self:GetTeamHurtCnt(BattleTeamSide.teamA)
        self._teamShowHurtCnt[BattleTeamSide.teamB] = self:GetTeamHurtCnt(BattleTeamSide.teamB)
    end
end

function LBattleViewMgr:AddShowHurtCnt(side,hurt)
    self:InitShowHurtCnt()

    local curHurtCnt = self._teamShowHurtCnt[side]
    curHurtCnt = curHurtCnt +  hurt

    self._teamShowHurtCnt[side] = curHurtCnt

    FireEvent(EventNames.BATTLE_HURT_MAX_COUNT_UPDATE)
end

function LBattleViewMgr:GetTeamHurtCnt(side)
    return self._teamHurtCnt[side] or 0
end

function LBattleViewMgr:GetTeamShowHurtCnt(side)
    return self._teamShowHurtCnt and self._teamShowHurtCnt[side] or 0
end

function LBattleViewMgr:GetMonsterAttrId(side)
    return self._battleReportData:GetMonsterAttrId(side)
end

function LBattleViewMgr:UpdateHeroDataBuffData()
    local round = self._round
    local nowRound = self._roundCount
    local checkBuff = false
    if(round ~= nowRound) then
        self._round = nowRound
        checkBuff = true
    end
    if checkBuff then
        for i, heroData in pairs(self._mapFormationData) do
            heroData:OnUpdateBuffRound(nowRound)
        end
        checkBuff = false
        FireEvent(EventNames.BUFF_UPDATE,true)--刷新buff回合数
    end
end

function LBattleViewMgr:OnRoundUpdate(round)
    for k,v in pairs(self._mapFormationData) do
        v:OnRoundUpdate(round)
    end
end

function LBattleViewMgr:OnObjRoundUpdate()
    local nowRound = self:GetRoundCount()
    local roundRecord = self._roundRecord
    if roundRecord == nowRound then
        return
    end
    self._roundRecord = nowRound
    local objList = self._unitMgr:GetUnitMap()
    for k,v in pairs(objList) do
        v:OnUpdateBuffRound(nowRound)
    end
end

------------------------------------------------------------------
---执行伤害表现

---@param actionData LFightBoutActionData
function LBattleViewMgr:DealShowAllActionEffects(actionData)
    local effectArrays = actionData.effectArrays
    for k,effectArrayData in ipairs(effectArrays) do
        self:DealShowHurt(effectArrayData)
    end

end
function LBattleViewMgr:ShowDealEffect()
    local warnEff = LFightWarn.New()
    self._deadWarnEff = warnEff
    self._deadWarnEff:Create(self:GetEffectRootTrans(), true, Vector3.zero)

    local dp = LDisplayEffect:New()
    self._deadEffect = dp
    dp:CreateEffect(self:GetEffectRootTrans(), "fx_manjingtou")
    dp:SetResTag(CS.RES_TAG_SCENE)
    dp:SetLoadedFunction(function()
        if self:IsDisposed() then return end
        if not self._deadEffect or not self._deadEffect:IsDpValid() then return end
        local dpTrans = self._deadEffect:GetDpTrans()
        local isWin = self._battleReportData:GetWinner() == 1
        local pos = Vector3(-2,0,0)
        if isWin then
            pos.x = 2
        end
        dpTrans.localPosition = pos
    end)
    dp:StartLoadEffect()


end

function LBattleViewMgr:StopDelayResetScaleTimer()
    if self._delayResetScaleTimer then
        MgrCenter.TimerMgr:RemoveTimer(self._delayResetScaleTimer)
        self._delayResetScaleTimer = nil
    end
end
function LBattleViewMgr:ShowLastEffect()
    if self._isLastEffShowed then return end

    self._isLastEffShowed = true
    self._isShowingLastEff = true
    self:ShowDealEffect()

    CtrlCenter.Battle:GetBattleMgr():SetTimeScale(0.3)

    self:StopDelayResetScaleTimer()

    self._delayResetScaleTimer = MgrCenter.TimerMgr:StartTimer(function()
        CtrlCenter.Battle:GetBattleMgr():SetTimeScale(1)
        self._isShowingLastEff = false
    end, 1.5, false)
end

---@param skillPlayer LBattleSkillPlayer
---@param effectArrayData LBattleEffectArrayData
function LBattleViewMgr:DealShowHurt(effectArrayData, bPlayHit, playNum, offsetPos, skillPlayer)
    if self._isLastAtk and not self._isAllboTarget then
        self:ShowLastEffect()
    end
    if not effectArrayData then return end
    bPlayHit = bPlayHit or LFightConst.PLAY_HIT_ACTION_NONE
    playNum = playNum or {}
    offsetPos = offsetPos or Vector3(0,0,0)
    --local hudCtrl = self:GetHudCtrl()
    --local intervalTime = 0.2
    local isBuffUpdate = false
    local isHurtType = false  -- 连击而且类型混杂的情况下，优先显示总伤害

    --local curOffset = offsetPos
    local isLogOpen= ENABLE_FIGHT_LOG
    local dataMgr = self._dataMgr

    local hudDataList ={}
    local time = self:GetTime()

    --local deadStateList = {}

    local heroRecord = {}

    for k, effectList in ipairs(effectArrayData.effectListArray) do
        --local eid = effectStruct.eid
        local list = self:RejectQueer(effectList.baseEffectList)
        --- 2024/7/9： http://192.168.16.2:3002/issues/838 护盾吸收伤害导致伤害<1时不飘免伤（客户端）
        ---@type boolean 是否为护盾格挡伤害，如果护盾格挡后还有伤害且为0，则不飘免伤

        ---@type boolean 护盾抵消伤害
        local isOffsetInjury = self:CheckOffsetInjury(list)
        
        for m,effect in ipairs(list) do
            local effectType = effect.type
            local atkHero = self:GetUnitView(effect.aId)
            local tarHero = self:GetUnitView(effect.eId)

            --local actionID = tonumber(effect.aId)
            if not tarHero or not tarHero:IsOnGridObj() then break end

            local atkSide = nil
            if atkHero then
                atkSide = atkHero:GetTeamIdx()
            else
                local side = tarHero:GetTeamIdx()
                atkSide = self:GetOppositeSide(side)
            end

            local tarPos = tarHero:GetTopNodePos()
            local pos = tarPos and tarPos:Clone() or Vector3.zero

            local hudData = nil

            if effectType == LFightConst.ACTIONEFFECTENUM_HURT then --伤害表现效果
                local hurtEffect = effect.hurtEffect
                local hurt = math.ceil(hurtEffect.hurt)
                local ht = hurtEffect.ht
                local dead = hurtEffect.dead
                local afterHp = hurtEffect.afterHp or 0
                --self:ChangeTeamHP(tarHero,afterHp,playNum,time)

                local tempPlayNum = playNum
                if ht == LFightConst.HURT_TYPE_PARRYING or ht == LFightConst.HURT_TYPE_BEHEAD
                        or LFightConst.NOT_SPLIT_PLAYNUM[ht] then
                    tempPlayNum ={}
                end

                if effect.hitType == 0 then --非技能对应伤害，不分段飘字
                    --- http://192.168.16.2:3002/issues/757
                    --- 此类多段伤害表现，在播放最后伤害受击后才倒地（相当于是打了空血条小人）
                    if type(playNum) == "table" and #playNum > 0 then
                    else
                        tempPlayNum = {}
                    end
                end

                tarHero:UpdateBlood(afterHp,tempPlayNum,time)

                if ht == LFightConst.HURT_TYPE_PARRYING then
                    --playNum = {}    -- 格挡不受配置次数影响
                    tarHero:UpdateBlockData()
                end

                local deadDelay = 0


                --- 2024/11/19：后端修改逻辑，以前 hurtEffect 的 dead 是先发 0 再发 1，现在直接下发 1
                ---@type boolean 是否显示飘血数据
                local showHudData = true
                if not dead then
                    if hurt < 1 and  ht ~= LFightConst.HURT_TYPE_PARRYING and ht ~= LFightConst.HURT_TYPE_MISS
                            --- http://192.168.16.2:3002/issues/705
                            --- 若CombatDamageTypeRef（伤害类型表）1004=护盾这种伤害，导致的本次伤害减免至0，不飘免伤表现buff_txt_shqm_1
                            and ht ~= LFightConst.HURT_TYPE_SHIELD
                            --- 2024/7/10：分摊<0的时候，不飘免伤
                            and ht ~= LFightConst.HURT_TYPE_DIVIDE_EQUALLY then
                        --优化需求 #1317:1. 当出现“因为免伤太高，把本次伤害减免至0”的时候，不飘伤害0，而变更为飘艺术字“伤害全免”（美术资源名：buff_txt_shqm_1）

                        --- 2024/9/11：普通伤害类型，排除飘免伤
                        if not isOffsetInjury and ht ~= LFightConst.HURT_TYPE_GENERAL_ATTACK then
                            hudData ={
                                targetHeroId = effect.eId ,
                                pos = pos+ offsetPos,
                                time = time,
                                --changeType = LFightConst.HURT_TIP,
                                changeType = 0,
                                text = "buff_txt_shqm_1"
                            }
                        end
                        showHudData = false
                    else
                        if ht == LFightConst.HURT_TYPE_DIVIDE_EQUALLY and hurt < 1 then
                            --- 分摊没有数值的话，直接取消飘字
                            showHudData = false
                        end
                    end
                else
                    deadDelay = dataMgr:GetTotalDelay(tempPlayNum)
                end

                if showHudData then
                    local text
                    local showType = ht
                    local actHurt = hurt
                    local isPARRYING = ht == LFightConst.HURT_TYPE_PARRYING
                    if isPARRYING then
                        actHurt = nil
                        local amageTypeRef = GameTable.BattleDamageTypeRef[showType]
                        text = amageTypeRef and amageTypeRef.name
                        showType = LFightConst.HURT_TIP
                    else
                        if actHurt and actHurt < 1 then
                            actHurt = nil
                            local amageTypeRef = GameTable.BattleDamageTypeRef[showType]
                            text = amageTypeRef and amageTypeRef.name
                            showType = LFightConst.HURT_TIP
                        end
                    end
                    hudData ={
                        targetHeroId = effect.eId ,
                        pos = pos+ offsetPos,
                        time = time,
                        hurt = actHurt,
                        changeType = showType,
                        isLeft = tarHero:GetTeamIdx() == BattleTeamSide.teamA,
                        playNum = tempPlayNum,
                        text = text,
                    }
                end

                if ht ~= LFightConst.HURT_TYPE_PARRYING then
                    isHurtType = true
                    self:ShowHurtCount(true,hurt,tempPlayNum,time,atkSide)
                end

                if dead then
                    isBuffUpdate = true
                    local canRelive = self:CheckCanRelive(effect.eId)
                    tarHero:DoDead(time,nil,canRelive,deadDelay)
                    --tarHero:PlayHitSound()
                    --优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
                    --hudData.hitAction = LFightConst.HIT_ACT_SOUND_ONLY
                end

                if hudData then
                    if ht ~= LFightConst.HURT_TYPE_MISS then
                        if bPlayHit == LFightConst.PLAY_HIT_ACTION_SKILL then	--播放技能受击动画
                            --tarHero:PlaySkillHitAni()
                            --tarHero:PlayHitSound()
                            --优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
                            hudData.hitAction = LFightConst.HIT_ACT_SOUND_AND_SKILLHIT

                        elseif bPlayHit == LFightConst.PLAY_HIT_ACTION_NORMAL then
                            --tarHero:PlayHitAni()
                            --tarHero:PlayHitSound()
                            --优化需求 #3967 【战斗系统】战斗多段表现伤害的受击效果优化
                            hudData.hitAction = LFightConst.HIT_ACT_SOUND_AND_HIT
                        end
                    end
                    --非技能对应伤害， 不播放受击
                    if not dead and effect.hitType == 0 and ht ~= LFightConst.HURT_TYPE_SPUTTERING then
                        hudData.hitAction = nil
                    end

                    --- 判断 buff 是否有受击特效
                    ---@param buffRef V_BuffRef
                    local isHasHitBuffEffShow,buffRef = tarHero:CheckHasHitBuffEffShow(ht)
                    if isHasHitBuffEffShow and buffRef ~= nil then
                        --- 受击时表现
                        local effectCtrl = self:GetEffectCtrl()
                        local buffEffPos = tarHero:GetPosition()
                        local effectRootTrans = tarHero:GetDpObject():GetDpTrans()
                        local buffEffShowPos = buffRef.buffEffShowPos
                        local localPos
                        if buffEffShowPos and buffEffShowPos > 0 then
                            local isFormation = buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER
                            if not isFormation then
                                local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
                                if buffShowPos then
                                    ---@type LDisplaySpine
                                    local tarHeroDP = tarHero:GetTransformDisplayObj()
                                    effectRootTrans = tarHeroDP:GetDpTrans()
                                    localPos = buffShowPos
                                end
                            end
                        end
                        ---@type LBattleViewEffect
                        local _buffEff = effectCtrl:MakeEffectObject(effectRootTrans,buffRef.buffEffShow,buffEffPos,tarHero:GetDirection(),0,2,0)
                        _buffEff:SetEffectPara({
                            scale = 1,
                            localPos = localPos,
                            buffId = buffRef.refId,
                        })
                        effectCtrl:AddEffect(_buffEff)
                    end
                end
            elseif effectType == LFightConst.ACTIONEFFECTENUM_TREATS then --治疗表现效果
                local treatEffect = effect.treatEffect
                local reliveSkillShow = false
                if treatEffect.express and treatEffect.express > 0 then
                    local skin = tarHero:GetSkinId()
                    local expressId = dataMgr:GetSkinExpress(skin,treatEffect.express)
                    if expressId then
                        local buffExpress = self._buffActMgr:GetBuffActQueue(expressId)
                        local para =
                        {
                            atkObj = atkHero,
                            targetObj = tarHero,
                            curTime = self:GetTime()
                        }
                        buffExpress:StartRun(para)
                        self._buffActMgr:AddRunningActQueue(buffExpress)
                        reliveSkillShow = true
                    end
                end

                local treat = math.ceil(treatEffect.treat)
                if treatEffect.isRelive then
                    --local noAct = effect.eId == effect.aId
                    tarHero:DoRelive(time,false,reliveSkillShow)
                    isBuffUpdate = true
                end


                local afterHp = treatEffect.afterHp or 0
                --self:ChangeTeamHP(tarHero,afterHp,playNum,time)
                local tempPlayNum = effect.hitType == 0 and {} or playNum

                tarHero:UpdateBlood(afterHp,tempPlayNum,time)

                if treat < 1 then
                    --优化需求 #1317:2. 当出现“因为受疗属性太低，把本次所受到的治疗值降成0”的时候，不飘回血0，而变更为飘艺术字“受疗缺失”（美术资源名：buff_txt_slqs_1）

                    --hudData ={
                    --	targetHeroId = effect.eId ,
                    --	pos = pos+ offsetPos,
                    --	time = time,
                    --	changeType = LFightConst.HURT_TIP,
                    --	text = "buff_txt_slqs_1",
                    --}
                else
                    hudData ={
                        targetHeroId = effect.eId ,
                        pos = pos+ offsetPos,
                        time = time,
                        hurt = treat,
                        changeType = LFightConst.HURT_TYPE_HEAL,
                        playNum =  tempPlayNum,
                        isLeft = tarHero:GetTeamIdx() == BattleTeamSide.teamA,
                    }
                end

                --addOffset = true

                if not isHurtType then
                    self:ShowHurtCount(false,treat,tempPlayNum,time,atkSide)
                end
            elseif effectType == LFightConst.ACTIONEFFECTENUM_BUFF then --buff表现效果
                local buffEffect = effect.buffEffect
                local buffId = buffEffect.buffId
                ---@type V_BuffRef
                local buffRefData = self:GetBuffRef(buffId)
                if buffRefData then
                    local buff = {}
                    buff.buffUniqueId = buffEffect.buffUniqueId
                    buff.buffId = buffId
                    buff.round = buffEffect.round
                    buff.startRound = self._roundCount == 0 and 1 or self._roundCount
                    buff.currentRound = buffEffect.round
                    tarHero:DoBuffUpdate(buff,buffEffect.etype)

                    self._buffEffectIs92 = self:CheckBuffEffectIs92(buffId)

                    local buffEffShow = buffRefData.buffEffShow
                    local isHasBuffEffShow = not string.isempty(buffEffShow)
                    local buffEffShowPos = buffRefData.buffEffShowPos
                    local isFormationBuff = buffEffShowPos == LFightConst.BUFF_POS_SELF or buffEffShowPos == LFightConst.BUFF_POS_OTHER
                    local showSide = atkSide
                    local buffEffShowType = buffRefData.buffEffShowType
                    if buffEffShowPos == LFightConst.BUFF_POS_OTHER then
                        showSide = self:GetOppositeSide(showSide)
                    end
                    local createBuffEff = false
                    local isAdd = buffEffect.etype == LFightConst.BUFF_TYPE_ADD
                    if isAdd then
                        if isHasBuffEffShow then
                            if isFormationBuff then
                                local isCreateEff = true
                                if buffEffShowType and buffEffShowType > 0 then
                                    local recordSideMap = self._recordBuffGroupMap[showSide]
                                    local recordBuffGroupMap = recordSideMap and recordSideMap[buffEffShowType]
                                    if recordBuffGroupMap ~= nil then
                                        isCreateEff = false
                                    end
                                end
                                if isCreateEff then
                                    local effectCtrl = self:GetEffectCtrl()
                                    ---@type LDisplaySpine
                                    local tarHeroDP = tarHero:GetTransformDisplayObj()
                                    local effectRootTrans = self:GetEffectRootTrans()
                                    local buffEffPos = self:GetFormationCenterPosition(showSide)
                                    local localPos
                                    if buffEffShowPos and buffEffShowPos > 0 and not tarHero:GetChangeSpineState() then
                                        local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
                                        if buffShowPos then
                                            effectRootTrans = tarHeroDP:GetDpTrans()
                                            buffEffPos = tarHero:GetPosition()
                                            localPos = buffShowPos
                                        end
                                    end
                                    ---@type LBattleViewEffect
                                    local _buffEff = effectCtrl:MakeEffectObject(effectRootTrans,buffEffShow,buffEffPos,atkHero:GetDirection(),0,2,0)
                                    _buffEff:SetEffectPara({
                                        scale = 1,
                                        isPersistence = buffEffect.round > 0,
                                        buffId = buffId,
                                    })
                                    effectCtrl:AddEffect(_buffEff)
                                    isCreateEff = true

                                    local tRecordSideMap = self._recordBuffGroupMap[showSide]
                                    if tRecordSideMap == nil then
                                        tRecordSideMap = {}
                                        self._recordBuffGroupMap[showSide] = tRecordSideMap
                                    end
                                    tRecordSideMap[buffEffShowType] = {
                                        effect = _buffEff,
                                    }
                                    createBuffEff = true
                                end
                            else
                                if buffEffShowType and buffEffShowType < 1 then
                                    --- 无分组
                                    local recordBuffCreateMap = self._recordBuffCreateMap
                                    if not recordBuffCreateMap then
                                        recordBuffCreateMap = {}
                                        self._recordBuffCreateMap = recordBuffCreateMap
                                    end
                                    local tarHeroId = tarHero:GetId()
                                    local recordIdMap = recordBuffCreateMap[tarHeroId]
                                    if not recordIdMap then
                                        recordIdMap = {}
                                        recordBuffCreateMap[tarHeroId] = recordIdMap
                                    end
                                    if not recordIdMap[buffId] then
                                        local effectCtrl = self:GetEffectCtrl()
                                        ---@type LDisplaySpine
                                        local tarHeroDP = tarHero:GetTransformDisplayObj()
                                        local tarHeroTrans = tarHeroDP:GetDpTrans()
                                        local tarHeroPos = tarHero:GetPosition()
                                        local localPos
                                        if buffEffShowPos and buffEffShowPos > 0 and not tarHero:GetChangeSpineState() then
                                            local buffShowPos = tarHero:GetBuffEffShowPosByBuffEffShowPos(buffEffShowPos,tarHero:GetObjScale())
                                            if buffShowPos then
                                                localPos = buffShowPos
                                            end
                                        end
                                        local startTime = 0
                                        local playTime = 2
                                        local direction = tarHero:GetDirection()
                                        ---@type LBattleViewEffect
                                        local _buffEff = effectCtrl:MakeEffectObject(tarHeroTrans,buffEffShow,tarHeroPos,direction,startTime,playTime,0)
                                        _buffEff:SetEffectPara({
                                            scale = 1,
                                            isPersistence = buffEffect.round > 0,
                                            targetObj = tarHero,
                                            localPos = localPos,
                                            buffId = buffId,
                                        })
                                        effectCtrl:AddEffect(_buffEff)
                                        recordIdMap[buffId] = {
                                            effect = _buffEff,
                                        }
                                    end
                                end
                            end
                        end
                    end

                    local id = tarHero:GetId()
                    if not createBuffEff then
                        heroRecord[id] = tarHero
                    end
                    local buffName = I18nText(buffRefData.name)
                    local isDead = tarHero:IsDead()
                    if isAdd then
                        local isShowAfterDead = dataMgr:IsShowAfterDead(buff.buffId)
                        if (isDead and isShowAfterDead) or (not isDead and not isShowAfterDead) then
                            local addOrReduceBuff = buffRefData.show
                            if not string.isempty(addOrReduceBuff) and buffEffect.show then
                                hudData = {
                                    targetHeroId = effect.eId ,
                                    pos = pos+ offsetPos,
                                    time = time,
                                    changeType = LFightConst.HURT_TYPE_BUFF,
                                    text = buffName,
                                    addOrReduceBuff = addOrReduceBuff,
                                }
                            end
                        end
                        ---buff 表现
                        local showEff = tarHero:GetShowEffRef()
                        local buffExpressId,showState = dataMgr:GetBuffSkillData(buffId,showEff.refId)
                        if buffExpressId then
                            if isLogOpen then
                                self:LogMsg(string.format("buff 技能表现 %s,%s,dead %s", tostring(buffExpressId), tostring(showState), tostring(isDead)))
                            end
                            if (isDead and showState == 2) or (not isDead and showState == 1) then
                                local buffExpress = self._buffActMgr:GetBuffActQueue(buffExpressId)
                                local para = {
                                    targetObj = tarHero,
                                    atkObj = atkHero,
                                    curTime = self:GetTime(),
                                    buffEffShowPos = buffEffShowPos,
                                }
                                buffExpress:StartRun(para)
                                self._buffActMgr:AddRunningActQueue(buffExpress)
                            end
                        end
                    elseif effect.etype == LFightConst.BUFF_TYPE_REMOVE then
                        ---buff 表现
                        if buffRefData.specialShow == 1 and not string.isempty(buffRefData.buffSkill) then
                            --- 可变身 且 buff 消散时表现
                            local showEff = tarHero:GetShowEffRef()
                            local buffExpressId,showState = dataMgr:GetBuffSkillData(buffId,showEff.refId)
                            if buffExpressId and buffExpressId > 0 then
                                if showState == 1 and not tarHero:IsDead() then
                                    --- 非死亡状态下
                                    if isLogOpen then
                                        self:LogMsg("变身回正常状态~~~~")
                                    end
                                    local buffExpress = self._buffActMgr:GetBuffActQueue(buffExpressId)
                                    local para = {
                                        targetObj = tarHero,
                                        atkObj = atkHero,
                                        curTime = self:GetTime(),
                                        buffEffShowPos = buffEffShowPos,
                                    }
                                    buffExpress:StartRun(para)
                                    self._buffActMgr:AddRunningActQueue(buffExpress)
                                end
                            end
                        end

                        if isHasBuffEffShow then
                            local side = tarHero:GetTeamIdx()
                            local recordSideMap = self._recordBuffGroupMap[side]
                            if recordSideMap then
                                local recordBuffGroupMap = recordSideMap[buffEffShowType]
                                if recordBuffGroupMap then
                                    local effectCtrl = self:GetEffectCtrl()
                                    effectCtrl:DestroyEffect(recordBuffGroupMap.effect)
                                    recordBuffGroupMap[buffId] = nil
                                end
                            end
                            local recordBuffCreateMap = self._recordBuffCreateMap
                            if recordBuffCreateMap then
                                local tarHeroId = tarHero:GetId()
                                local recordIdMap = recordBuffCreateMap[tarHeroId]
                                if recordIdMap and recordIdMap[buffId] then
                                    local effectCtrl = self:GetEffectCtrl()
                                    effectCtrl:DestroyEffect(recordIdMap[buffId].effect)
                                    recordBuffCreateMap[tarHeroId][buffId] = nil
                                end
                            end
                        end
                        --self:InsertWaitRemove(effect.buffUniqueId)
                    end
                    isBuffUpdate = true
                end
            elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELD then --护盾表现效果
                local shieldEffect = effect.shieldEffect
                local shield = {}
                shield.buffUniqueId = shieldEffect.buffUniqueId
                shield.shieldUniqueId = shieldEffect.shieldUniqueId
                if isLogOpen then
                    local str = string.format("新增护盾的唯一ID：%s 护盾值 %s ",tostring(shieldEffect.shieldUniqueId),tostring(shieldEffect.hp))
                    self:LogMsg(str)
                end
                shield.maxHP = shieldEffect.hp
                shield.curHP = shieldEffect.hp
                tarHero:AddShieldData(shield)
            elseif effectType == LFightConst.ACTIONEFFECTENUM_PSHIELD then --格挡盾表现效果
                local pShieldEffect = effect.pShieldEffect
                local block = {}
                block.buffUniqueId = pShieldEffect.buffUniqueId
                block.blockUniqueId = pShieldEffect.blockUniqueId
                block.maxCount = pShieldEffect.count
                block.curCount = pShieldEffect.count
                tarHero:AddBlockData(block)

            elseif effectType == LFightConst.ACTIONEFFECTENUM_ANGER then --怒气表现效果
                local angerEffect = effect.angerEffect
                local anger = {}
                anger.buffUniqueId = angerEffect.buffUniqueId
                anger.angerValue = angerEffect.angerValue
                if isLogOpen then
                    local str = string.format("当前怒气：%s 层，怒气关联buff的唯一ID：%s ",tostring(anger.angerValue),tostring(angerEffect.buffUniqueId))
                    self:LogMsg(str)
                end
                tarHero:AddAngerData(anger)

            elseif effectType == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then --护盾抵挡伤害表现效果
                local shieldHurtEffect = effect.shieldHurtEffect
                local shield = {}
                shield.shieldUniqueId = shieldHurtEffect.shieldUniqueId
                shield.hurt = -shieldHurtEffect.hurt
                if isLogOpen then
                    local str = string.format("护盾抵挡伤害：%s 护盾唯一ID：%s ",tostring(shield.hurt),tostring(shieldHurtEffect.shieldUniqueId))
                    self:LogMsg(str)
                end
                hudData =
                {
                    targetHeroId = effect.eId ,
                    pos = pos+ offsetPos,
                    time = time,
                    hurt = shieldHurtEffect.hurt,
                    changeType = LFightConst.HURT_TYPE_SHIELD,
                    playNum = playNum,
                }
                tarHero:UpdateShieldData(shield)

                --addOffset = true
            elseif effectType == LFightConst.ACTIONEFFECTENUM_POSITION then --站位变化
                local positionEffect = effect.positionEffect
                local totalTime = (#(positionEffect.wayIndexList or {}) +1) * 0.5
                local side = tarHero:GetTeamType()
                local para =
                {
                    side = side,
                    effect = effect,
                    duration =totalTime,
                    endTime = time + totalTime,
                }

                self._buffActMgr:StartPositionAct(para)
            elseif effectType == LFightConst.ACTIONEFFECTENUM_SUMMON then
                self:AddSummonHero(effect)
            elseif effectType == LFightConst.ACTIONEFFECTENUM_ROUND then
                tarHero:UpdateBuffData(effect)
            end

            if hudData and not hudData.changeType then
                if isLogOpen then
                    self:LogMsg("飘字的类型为空")
                end
            end

            if hudData then
                local target = hudData.targetHeroId
                local list = hudDataList[target]
                if not list then
                    list = {}
                    hudDataList[target] = list
                end

                table.insert(list,hudData)
            end

        end


    end

    for k,v in pairs(hudDataList) do
        local tarHero = self:GetUnitView(k)
        if tarHero then
            tarHero:ShowHud(v, time, skillPlayer)
        end
    end


    for k,v in pairs(heroRecord) do
        v:RefreshAfter()
    end

    if isBuffUpdate then
        FireEvent(EventNames.BATTLE_BUFF_UPDATE,true)
    end

end


---@param list LBattleBaseEffectData[]
---@return LBattleBaseEffectData[]
function LBattleViewMgr:RejectQueer(list)
    list = list or {}
    local resultList = {}
    for i,effect in ipairs(list) do
        local tarHero = self:GetUnitView(effect.eId)
        if not tarHero or not tarHero:IsOnGridObj() then
        else
            table.insert(resultList,effect)
        end
    end
    return resultList
end

--- 2024/7/10：判断是否护盾抵消伤害
---@param list LBattleBaseEffectData[]
function LBattleViewMgr:CheckOffsetInjury(list)
    local hasShieldHurt = false
    local recordHurt = 0
    list = list or {}
    for i,effect in ipairs(list) do
        if effect.type == LFightConst.ACTIONEFFECTENUM_HURT then --伤害表现效果
            recordHurt = recordHurt + math.ceil(effect.hurtEffect.hurt)
        elseif effect.type == LFightConst.ACTIONEFFECTENUM_SHIELDHURT then
            if not hasShieldHurt then hasShieldHurt = true end
        end
    end
    return hasShieldHurt and recordHurt < 1 or false
end





function LBattleViewMgr:ShowHurtCount(isHurt,num,playNum,time,side)
    self:ClearHurtCntList()

    local change = num
    local dataList = {}
    local sTime = time
    local totalRatio = 1
    local data =nil
    local totalHurt = 0
    local tempTime = sTime
    if playNum and #playNum>0 then

        for i, v in ipairs(playNum) do
            local showNum = math.floor(v[2]* change)
            data =
            {
                isHurt = isHurt,
                startTime = tempTime,
                showNum = showNum,
                side = side,
            }
            tempTime = sTime+ v[1]
            table.insert(dataList,data)
            totalRatio = totalRatio - v[2]
            totalHurt = totalHurt+ showNum
        end
    end

    local leftHurt = change - totalHurt
    if leftHurt >0 then
        data =
        {
            isHurt = isHurt,
            startTime = tempTime,
            showNum = leftHurt,
            side = side
        }
        table.insert(dataList,data)
    end

    self._hurtCntList = dataList
end

function LBattleViewMgr:ClearHurtCntList()
    if self._hurtCntList and #self._hurtCntList>0 then
        local isHurt = nil
        local totalNum = 0
        local side = nil
        for k,v in ipairs(self._hurtCntList) do
            totalNum = totalNum+ v.showNum
            isHurt = v.isHurt
            side = v.side
        end

        self._hurtCounter:AddHurtCount(side,isHurt,totalNum)
        if side and isHurt then
            self:AddShowHurtCnt(side,totalNum)
        end
        self._hurtCntList = nil
    end
end

function LBattleViewMgr:UpdateHurtCount(time)
    if self._hurtCntList then
        local first = self._hurtCntList[1]
        if first then
            if first.startTime <= time then
                self._hurtCounter:AddHurtCount(first.side,first.isHurt,first.showNum)
                table.remove(self._hurtCntList,1)
                if first.side and first.isHurt then
                    self:AddShowHurtCnt(first.side,first.showNum)
                end
            end
        end
    end
end



