function LBattleViewMgr:InitTeamHP()
    self._teamHPCountA = 0
    self._teamHPCountB = 0
    self._teamHPA = 0
    self._teamHPB = 0

    ---@type LBattleLogicUnit[]
    local formationA = self:GetFormationA()
    ---@type LBattleLogicUnit[]
    local formationB = self:GetFormationB()

    for i,heroData in pairs(formationA) do
        self._teamHPCountA = self._teamHPCountA + heroData.maxHp
        self._teamHPA = self._teamHPA + heroData.hp
    end

    for i,heroData in pairs(formationB) do
        self._teamHPCountB = self._teamHPCountB + heroData.maxHp
        self._teamHPB = self._teamHPB + heroData.hp
    end

    --FireEvent(EventNames.BLOOD_INIT,true)
end

