        if player then
            player:Dispose()
        end
    end
end


function LBattleViewMgr:CalcOfflineRoundCount()
    if self._offlineTime<= 0 then
        return
    end

    local ref = GameTable.BattleGameRef[self._combatType]
    if not ref then
        return
    end

    local roundDataList = self._battleReportData:GetRoundDataList()
    local roundCount = #roundDataList

    local timeout = ref.timeout
    local offlineRound = math.floor(self._offlineTime/timeout*roundCount)
    offlineRound = offlineRound >= self._totalRoundIndex and self._totalRoundIndex -1 or offlineRound --防止死循环
    self._offlineTime = 0

    self._offlineRound = offlineRound
end
