function LBattleViewMgr:Dispose()
    if self._isDisposed then
        return
    end
    if LOG_INFO_ENABLED then
        printInfo("battle", "LBattleViewMgr Dispose")
    end

    self:ClearSeqCom()

    if self._agent then
        self._agent:SetViewMgr(nil)
    end

    local effectCtrl = self:GetEffectCtrl()
    for showSide,v in pairs(self._recordBuffGroupMap) do
        for buffEffShowType,v1 in pairs(v) do
            effectCtrl:DestroyEffect(v1.effect)
        end
    end

    self:StopDelayResetScaleTimer()


    self:ClearSkillPlayers()

    self:ClearPreloadSkill()

    if self._unitMgr then
        self._unitMgr:Dispose()
    end
    if self._effectMgr then
        self._effectMgr:Dispose()
    end
    if self._viewFace then
        self._viewFace:Dispose()
    end

    if self._treaObjCtrl then
        self._treaObjCtrl:Dispose()
    end

    if self._deadEffect then
        self._deadEffect:Dispose()
    end

    if self._deadWarnEff then
        self._deadWarnEff:Dispose()
    end

    if self._buffActMgr then
        self._buffActMgr:Dispose()
    end

    if self._decoraCtrl then
        self._decoraCtrl:Dispose()
    end

    table.dispose(self)

    self._isDisposed = true
end

