function LBattleViewMgr:S2C_OnPlayActionList(atkSide, isOfflineRound, skillDataList, roundIndex, boutIndex, actionIndex)
    self._curRoundIndex = roundIndex
    self._curBout = boutIndex
    self._curAction = actionIndex

    self:ClearHurtCntList()

    if not self._buffEffectIs92 then
        self._hurtCounter:EndCounter()
    end
    self._buffEffectIs92 = false

    self._hurtCounter:StartCounter(atkSide) --设置伤害统计目标

    -- 离线战斗回来要追平至离线回合
    if isOfflineRound then
        --更新血量,生存状态
        local objList = self._unitMgr:GetUnitMap()
        for k,v in pairs(objList) do
            v:SynOfflineState(0)
        end

        if self._agent then
            self._agent:C2S_SetViewActFinish(true)
        end
        return
    end

    if self._agent then
        self._agent:C2S_SetViewActFinish(false)
    end

    ---清理当前技能表现
    self:ClearSkillPlayers()

    local players = nil
    local preloadSkill = self._preloadSkill
    if preloadSkill then
        local state = self:GetPreloadState(preloadSkill,self._curRoundIndex, self._curBout, self._curAction)
        if state == 1 then
            self:ClearPreloadSkill()
        elseif state == 2 then
            players = preloadSkill.skillList
            self._preloadSkill = nil
        end
    end

    ---@type LBattleSkillPlayer
    local player

    local skillIdMap = {}
    local skillRefId = nil
    local bUseSkillMap = {}
    local bUseSKillIdMap = {}
    local index = 1
    for i, v in ipairs(skillDataList) do
        local skillData = v.skillData
        if not skillData then -- 没有表现数据 直接执行伤害飘字
            self:DealShowAllActionEffects(v.actionData)
        else
            if players then
                player = players[index]
                if player then
                    bUseSkillMap[index] = true
                    table.insert(self._runningSkillPlayers, player)
                    bUseSKillIdMap[skillData:GetSkillRefId()] = true

                    skillRefId = player:GetSkillId()
                    local noSkillHud = false
                    if skillIdMap[skillRefId] then
                        noSkillHud = true
                    end
                    skillIdMap[skillRefId] = true

                    local curSkillData = player:GetSkillData()
                    if curSkillData and curSkillData:GetSkillRefId() ~= skillData:GetSkillRefId() then
                        if LOG_INFO_ENABLED then
                            printInfo("battle",">> 原技能RefId:" .. tostring(curSkillData:GetSkillRefId()) .. "，当前技能RefId:" .. tostring(skillData:GetSkillRefId()))
                        end
                        player:UpdateSkillData(skillData,self:GetUnitView(v.aId),v.actionData)
                    end

                    FireEvent(EventNames.BATTLE_HERO_PLAY,v.aId)

                    player:Start(noSkillHud)
                    index = index + 1
                end
            else
                local atkObj = self:GetUnitView(v.aId)		-- 没有出手英雄，也直接执行伤害飘字
                if atkObj then
                    player = LBattleSkillPlayer:new(self)
                    player:Initialize(skillData,atkObj,v.actionData)
                    table.insert(self._runningSkillPlayers, player)

                    skillRefId = player:GetSkillId()
                    local noSkillHud = false
                    if skillIdMap[skillRefId] then
                        noSkillHud = true
                    end
                    skillIdMap[skillRefId] = true

                    FireEvent(EventNames.BATTLE_HERO_PLAY,v.aId)

                    player:Start(noSkillHud)
                else
                    self:DealShowAllActionEffects(v.actionData)
                end
            end
        end
    end

    if players then
        for k,v in pairs(players) do
            if not bUseSkillMap[k] then
                v:Dispose()
            end
        end
    end

    if self._runningSkillPlayers and #self._runningSkillPlayers > 0 then
        ---@param v LBattleSkillPlayer
        for i,v in ipairs(self._runningSkillPlayers) do
            v:UpdateHeroesBgState()
        end
    end
    --self:PreloadRoundPlay(self._curRoundIndex, self._curBout, self._curAction + 1)

end


function LBattleViewMgr:S2C_OnBattleStart(reportData)
    FireEvent(EventNames.BATTLE_SHOW_START, reportData)
    self._time = 0
end

function LBattleViewMgr:S2C_UpdateHeroPlay(recordPlayHeroId)
    FireEvent(EventNames.BATTLE_HERO_PLAY,recordPlayHeroId)
end

function LBattleViewMgr:S2C_UpdateBuffData()
    FireEvent(EventNames.BATTLE_BUFF_UPDATE,true)--刷新buff回合数
end

function LBattleViewMgr:S2C_UpdateTreasureCD()
    FireEvent(EventNames.BATTLE_SKILL_LIST_UPDATE)
end
---@endregion S2C接口


return LBattleViewMgr